<script lang="ts">
import { defineComponent } from "vue";
import AddSupportModal from "./AddSupportModal.vue";
import SupportCard from "./SupportCard.vue";
import SupportCardJson from "@/assets/support_card_data.json";

// [speed, stamina, power, guts, wiz, skillPt, vital]
const trainingEffect = [
  [
    [10, 0, 5, 0, 0, 2, -21],
    [11, 0, 5, 0, 0, 2, -22],
    [12, 0, 5, 0, 0, 2, -23],
    [13, 0, 6, 0, 0, 2, -25],
    [14, 0, 7, 0, 0, 2, -27],
  ],
  [
    [0, 9, 0, 4, 0, 2, -19],
    [0, 10, 0, 4, 0, 2, -20],
    [0, 11, 0, 4, 0, 2, -21],
    [0, 12, 0, 5, 0, 2, -23],
    [0, 13, 0, 6, 0, 2, -25],
  ],
  [
    [0, 5, 8, 0, 0, 2, -20],
    [0, 5, 9, 0, 0, 2, -21],
    [0, 5, 10, 0, 0, 2, -22],
    [0, 6, 11, 0, 0, 2, -24],
    [0, 7, 12, 0, 0, 2, -26],
  ],
  [
    [4, 0, 4, 8, 0, 2, -22],
    [4, 0, 4, 9, 0, 2, -23],
    [4, 0, 4, 10, 0, 2, -24],
    [5, 0, 4, 11, 0, 2, -26],
    [5, 0, 5, 12, 0, 2, -28],
  ],
  [
    [2, 0, 0, 0, 9, 4, 5],
    [2, 0, 0, 0, 10, 4, 5],
    [2, 0, 0, 0, 11, 4, 5],
    [3, 0, 0, 0, 12, 4, 5],
    [4, 0, 0, 0, 13, 4, 5],
  ],
];

const trainingTypes = [
  { label: "スピード", value: 0 },
  { label: "スタミナ", value: 1 },
  { label: "パワー", value: 2 },
  { label: "根性", value: 3 },
  { label: "賢さ", value: 4 },
];

const motivations = [
  { label: "絶好調", value: 20 },
  { label: "好調", value: 10 },
  { label: "普通", value: 0 },
  { label: "不調", value: -10 },
  { label: "絶不調", value: -20 },
];

type CardInfo = { detail: typeof SupportCardJson[number]; diamond: number; level: number };

export default defineComponent({
  components: {
    AddSupportModal,
    SupportCard,
  },

  emits: ["updateSavedDecks"],

  data: function () {
    type DeckType = { name: string; deck: { id: number; diamond: number; level: number }[] };
    let cards: (CardInfo | null)[] = [null, null, null, null, null, null];
    let cardRefs: typeof SupportCard[] = [];
    let savedDecks: DeckType[] = [];

    return {
      cards,
      cardRefs,
      selectedIndex: 0,
      deckName: "",
      selectedDeckName: "",
      showUpdateCardModal: false,
      showDeckNameModal: false,
      savedDecks,
      trainingTypes,
      trainingValue: 0,
      trainingLevel: "5",
      motivations,
      motivationValue: 20,
      publicPath: process.env.BASE_URL,
    };
  },

  props: {
    displayContent: {
      type: String,
      required: true,
    },
    left: {
      type: Boolean,
      required: true,
    },
  },

  computed: {
    cardEffectArray: function (): number[][] {
      let result: number[][] = [];

      for (const card of this.cards) {
        if (card == null) {
          result.push([]);
          continue;
        }

        let effectArray = new Array<number>(32).fill(0);

        // support effects
        for (const supportEffect of card.detail.effect) {
          let lo = { lv: -1, value: -1 };
          let hi = { lv: -1, value: -1 };

          for (let i = card.level / 5; i >= 0; --i) {
            if (supportEffect.value[i] !== -1) {
              lo = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          for (let i = card.level / 5; i <= 10; ++i) {
            if (supportEffect.value[i] !== -1) {
              hi = { lv: i * 5, value: supportEffect.value[i] };
              break;
            }
          }

          if (lo.value === -1) {
            // do nothing
          } else if (hi.value === -1 || lo.lv == hi.lv) {
            effectArray[supportEffect.type] = lo.value;
          } else {
            const v = lo.value + ((card.level - lo.lv) * (hi.value - lo.value)) / (hi.lv - lo.lv);
            effectArray[supportEffect.type] = Math.floor(v);
          }
        }

        // unique effects
        if (card.detail.unique != null && card.level >= card.detail.unique.lv) {
          for (const uniqueEffect of card.detail.unique.effect) {
            const ty = uniqueEffect.type;
            if ([1, 19].includes(ty) && effectArray[ty] !== 0) {
              // 友情ボーナス / 得意率
              const v = ((100 + effectArray[ty]) * (100 + uniqueEffect.value) - 10000) / 100;
              effectArray[ty] = v;
            } else {
              effectArray[ty] += uniqueEffect.value;
            }
          }
        }

        result.push(effectArray);
      }

      return result;
    },

    cardStatTexts: function (): ({ icon: number[]; text: string }[] | null)[] {
      let stats: ({ icon: number[]; text: string }[] | null)[] = [];

      for (let i = 0; i < 6; ++i) {
        // null
        if (this.cards[i] == null) {
          stats.push(null);
          continue;
        }

        let stat: { icon: number[]; text: string }[] = [];
        const effectPer = [1, 2, 8, 15, 16, 18, 25, 26, 27, 28];
        const defaultPush = (index: number) => {
          const text =
            this.cardEffectArray[i][index] === 0
              ? "-"
              : (effectPer.includes(index) ? "" : "+") +
                this.cardEffectArray[i][index].toString() +
                (effectPer.includes(index) ? "%" : "");
          stat.push({ icon: [], text });
        };

        defaultPush(1); // 友情
        defaultPush(2); // やる気

        // 練習ボーナス
        let trainingBonus: { icon: number[]; text: string } | null = null;
        for (let j = 3; j < 8; ++j) {
          if (this.cardEffectArray[i][j] > 0) {
            if (trainingBonus == null) {
              trainingBonus = { icon: [j - 3], text: "+" + this.cardEffectArray[i][j].toString() };
            } else {
              if (trainingBonus.text !== "+" + this.cardEffectArray[i][j].toString()) {
                trainingBonus = { icon: [], text: "Error!" };
                break;
              }
              trainingBonus.icon.push(j - 3);
            }
          }
        }
        stat.push(trainingBonus ?? { icon: [], text: "-" });

        defaultPush(8); // トレ効果

        // 初期ボーナス
        let initialBonus: { icon: number[]; text: string } | null = null;
        for (let j = 9; j < 14; ++j) {
          if (this.cardEffectArray[i][j] > 0) {
            if (initialBonus == null) {
              initialBonus = { icon: [j - 9], text: "+" + this.cardEffectArray[i][j].toString() };
            } else {
              if (initialBonus.text !== "+" + this.cardEffectArray[i][j].toString()) {
                initialBonus = { icon: [], text: "Error!" };
                break;
              }
              initialBonus.icon.push(j - 9);
            }
          }
        }
        stat.push(initialBonus ?? { icon: [], text: "-" });

        defaultPush(14); // 初期絆
        defaultPush(15); // レース
        defaultPush(16); // ファン数
        defaultPush(17); // ヒントLv
        defaultPush(18); // ヒント発生率
        defaultPush(19); // 得意率
        defaultPush(25); // イベ回復量
        defaultPush(26); // イベ効果
        defaultPush(27); // 失敗率
        defaultPush(28); // 体力消費
        defaultPush(30); // スキルPt
        defaultPush(31); // 賢さ友情回復量

        stats.push(stat);
      }

      return stats;
    },

    trainingStats: function (): {
      effectText: string[];
      baseEffect: number[];
      averageEffect: number[];
      top50Effect: number[];
      top30Effect: number[];
      consumeVital: number;
      tagNumRates: number[];
    } {
      let appearRates: number[] = [];
      let allAppearRate = 1.0;
      let tagTrainingMaxNum = 0;

      for (let i = 0; i < 6; ++i) {
        let appearRate = 0.0;
        if (this.cards[i] != null) {
          let numer = 100;
          const denom = 550 + this.cardEffectArray[i][19];
          if (this.trainingValue === this.cards[i]?.detail.command_id) {
            numer += this.cardEffectArray[i][19];
            tagTrainingMaxNum += 1;
          }
          appearRate = numer / denom;
        }
        appearRates.push(appearRate);
        allAppearRate *= appearRate;
      }

      tagTrainingMaxNum = Math.min(tagTrainingMaxNum, 5);
      let results: { rate: number; effect: number[] }[] = [];
      let tagNumRates = new Array<number>(tagTrainingMaxNum + 1).fill(0);

      for (let bitmask = 0; bitmask < 63; ++bitmask) {
        let rate = 1.0 / (1.0 - allAppearRate);
        for (let i = 0; i < 6; ++i) {
          rate *= ((bitmask >> i) & 1) === 1 ? appearRates[i] : 1 - appearRates[i];
        }
        if (rate === 0.0) continue;

        let effect = trainingEffect[this.trainingValue][+this.trainingLevel - 1].slice();

        // 基礎ボーナス
        for (let i = 0; i < 6; ++i) {
          if (((bitmask >> i) & 1) === 1) {
            for (let j = 0; j < 5; ++j) {
              if (effect[j] > 0 && this.cardEffectArray[i][j + 3]) {
                effect[j] += this.cardEffectArray[i][j + 3];
              }
            }
          }
        }

        // 友情ボーナス
        let tagNum = 0;
        for (let i = 0; i < 6; ++i) {
          if (((bitmask >> i) & 1) === 1) {
            if (this.trainingValue === this.cards[i]?.detail.command_id) {
              tagNum += 1;
              for (let j = 0; j < 5; ++j) {
                effect[j] *= (100 + this.cardEffectArray[i][1]) / 100;
              }
            }
          }
        }
        tagNumRates[tagNum] += rate;

        // やる気効果
        let motivationCoef = 100;
        for (let i = 0; i < 6; ++i) {
          if (((bitmask >> i) & 1) === 1) {
            motivationCoef += this.cardEffectArray[i][2];
          }
        }
        for (let j = 0; j < 5; ++j) {
          effect[j] *= (10000 + this.motivationValue * motivationCoef) / 10000;
        }

        // トレーニング効果
        let trainingCoef = 100;
        for (let i = 0; i < 6; ++i) {
          if (((bitmask >> i) & 1) === 1) {
            trainingCoef += this.cardEffectArray[i][8];
          }
        }
        for (let j = 0; j < 5; ++j) {
          effect[j] *= trainingCoef / 100;
        }

        // 人数補正
        let numCoef = 100;
        for (let i = 0; i < 6; ++i) {
          if (((bitmask >> i) & 1) === 1) {
            numCoef += 5;
          }
        }
        for (let j = 0; j < 5; ++j) {
          effect[j] *= numCoef / 100;
        }

        // 切り捨て & キャップ
        for (let j = 0; j < 5; ++j) {
          effect[j] = Math.min(Math.floor(effect[j]), 100);
        }

        results.push({ rate, effect });
      }

      results.sort((lhs, rhs) => {
        let lhsSum = 0;
        let rhsSum = 0;
        let lhsMax = 0;
        let rhsMax = 0;
        for (let i = 0; i < 5; ++i) {
          lhsSum += lhs.effect[i];
          rhsSum += rhs.effect[i];
          lhsMax = Math.max(lhsMax, lhs.effect[i]);
          rhsMax = Math.max(rhsMax, rhs.effect[i]);
        }
        return (rhsSum - lhsSum) * 1000 + (rhsMax - lhsMax);
      });

      let averageEffect = new Array<number>(5).fill(0);
      let top50Effect = new Array<number>(5).fill(0);
      let top30Effect = new Array<number>(5).fill(0);
      let count50 = 0.5;
      let count30 = 0.3;

      for (const result of results) {
        for (let i = 0; i < 5; ++i) {
          averageEffect[i] += result.rate * result.effect[i];
          top50Effect[i] += (Math.min(count50, result.rate) * result.effect[i]) / 0.5;
          top30Effect[i] += (Math.min(count30, result.rate) * result.effect[i]) / 0.3;
        }
        count50 = Math.max(count50 - result.rate, 0);
        count30 = Math.max(count30 - result.rate, 0);
      }

      averageEffect = averageEffect.filter((val) => val > 0);
      top50Effect = top50Effect.filter((val) => val > 0);
      top30Effect = top30Effect.filter((val) => val > 0);

      let effectText: string[] = [];
      let baseEffect: number[] = [];
      for (let i = 0; i < 5; ++i) {
        let effectValue = trainingEffect[this.trainingValue][+this.trainingLevel - 1][i];
        if (effectValue > 0) {
          effectText.push(["スピード", "スタミナ", "パワー", "根性", "賢さ"][i]);
          baseEffect.push(effectValue);
        }
      }

      const consumeVital = trainingEffect[this.trainingValue][+this.trainingLevel - 1][6];

      return {
        effectText,
        baseEffect,
        averageEffect,
        top50Effect,
        top30Effect,
        consumeVital,
        tagNumRates,
      };
    },
  },

  methods: {
    updateCard: function (index: number) {
      this.selectedIndex = index;
      this.showUpdateCardModal = true;
    },

    select: function (arg: CardInfo | null) {
      this.cards[this.selectedIndex] = arg;
    },

    loadDeck: function () {
      if (this.selectedDeckName === "") return;

      let selectedDeck: { id: number; diamond: number; level: number }[] = [];
      for (const deck of this.savedDecks) {
        if (deck.name === this.selectedDeckName) {
          selectedDeck = deck.deck;
          break;
        }
      }

      const supportCards = Object.fromEntries(SupportCardJson.map((card) => [card.id, card]));
      for (let i = 0; i < 6; ++i) {
        if (selectedDeck[i].id === -1) {
          this.cards[i] = null;
        } else {
          this.cards[i] = {
            detail: supportCards[selectedDeck[i].id],
            diamond: selectedDeck[i].diamond,
            level: selectedDeck[i].level,
          };
        }
      }
    },

    saveDeck: function () {
      this.showDeckNameModal = true;
      this.deckName = this.selectedDeckName;
      setTimeout(() => (this.$refs.deckNameInput as HTMLInputElement).focus(), 10);
    },

    saveDeckName: function () {
      if (this.deckName === "") return;

      let deck: { id: number; diamond: number; level: number }[] = [];
      for (const card of this.cards) {
        if (card == null) {
          deck.push({ id: -1, diamond: -1, level: -1 });
        } else {
          deck.push({ id: card.detail.id, diamond: card.diamond, level: card.level });
        }
      }

      let updated = false;
      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.deckName) {
          updated = true;
          this.savedDecks[i].deck = deck;
        }
      }

      if (!updated) {
        this.savedDecks.push({ name: this.deckName, deck });
      }

      this.selectedDeckName = this.deckName;
      this.closeDeckNameModal();

      localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
      this.$emit("updateSavedDecks");
    },

    closeDeckNameModal: function () {
      this.deckName = "";
      this.showDeckNameModal = false;
    },

    removeDeck: function () {
      if (this.selectedDeckName === "") return;

      for (let i = 0; i < this.savedDecks.length; ++i) {
        if (this.savedDecks[i].name === this.selectedDeckName) {
          this.savedDecks.splice(i, 1);
          break;
        }
      }

      this.selectedDeckName = "";
      if (this.savedDecks.length > 0) {
        localStorage.setItem("savedDecks", JSON.stringify(this.savedDecks));
      } else {
        localStorage.removeItem("savedDecks");
      }
      this.$emit("updateSavedDecks");
    },

    resetDeck: function () {
      this.cards = [null, null, null, null, null, null];
      this.selectedDeckName = "";
    },

    loadLocalStorage: function () {
      const data = localStorage.getItem("savedDecks");
      if (data != null) {
        try {
          this.savedDecks = JSON.parse(data);
        } catch (e) {
          this.savedDecks = [];
          localStorage.removeItem("savedDecks");
        }
      } else {
        this.savedDecks = [];
      }
    },

    reloadLocalStorage: function () {
      this.loadLocalStorage();
      let found = false;

      for (const deck of this.savedDecks) {
        if (deck.name === this.selectedDeckName) {
          found = true;
          for (let i = 0; i < 6; ++i) {
            found &&=
              (deck.deck[i].id === -1 && this.cards[i] == null) ||
              (deck.deck[i].id === this.cards[i]?.detail.id &&
                deck.deck[i].diamond === this.cards[i]?.diamond);
          }
          break;
        }
      }

      if (!found) {
        this.selectedDeckName = "";
      }
    },

    updateCardsFontSize: function () {
      for (const el of this.cardRefs) {
        el.updateFontSize();
      }
    },
  },

  mounted: function () {
    this.loadLocalStorage();
  },

  beforeUpdate: function () {
    this.cardRefs = [];
  },
});
</script>

