<template>
  <div
    :class="
      'sticky xl:static top-12 z-10 md:top-14 flex xl:hidden ' +
      'items-center justify-center mx-auto pt-5 sm:pt-8 pb-4 sm:pb-6'
    "
    style="background-color: #f9f8fd"
  >
    <div class="flex justify-end w-24 sm:w-28 text-sm sm:text-base">
      <label class="cursor-pointer" @click="showSecondDeck = false">デッキ1</label>
    </div>
    <label class="flex items-center cursor-pointer mx-5 sm:mx-7">
      <div class="relative">
        <input type="checkbox" v-model="showSecondDeck" class="sr-only" />
        <div class="w-9 sm:w-12 h-3 sm:h-4 bg-gray-400 rounded-full shadow-inner" />
        <div
          :class="
            'absolute w-4.5 sm:w-6 h-4.5 sm:h-6 bg-white rounded-full ' +
            'border border-gray-600 shadow -left-1 -top-0.75 sm:-top-1 transition dot'
          "
        />
      </div>
    </label>
    <div class="flex justify-start w-24 sm:w-28 text-sm sm:text-base">
      <label class="cursor-pointer" @click="showSecondDeck = true">デッキ2</label>
    </div>
  </div>

  <div class="xl:grid xl:grid-cols-11 mx-auto xl:mt-6 max-w-screen-2xl">
    <!-- Deck 1 -->
    <div
      class="xl:col-span-5 flex-col items-center"
      :class="{
        flex: !showSecondDeck,
        hidden: showSecondDeck,
        'xl:flex': showSecondDeck,
      }"
    >
      <deck-info
        ref="firstDeck"
        :displayContent="displayContent"
        :left="true"
        @updateSavedDecks="updateSavedDecksFirst"
      />
    </div>

    <!-- Middle -->
    <div class="hidden xl:flex flex-col items-center font-bold">
      <div class="flex items-center h-32 mb-2">
        <div>デッキ</div>
      </div>

      <div class="flex items-center h-12 mb-4"></div>

      <div v-if="displayContent === 'effect'" class="flex flex-col items-center w-full">
        <div
          v-for="i in 17"
          :key="i"
          class="flex items-center justify-center h-8 w-full"
          :class="i % 2 === 1 ? 'bg-gray-200' : ''"
        >
          <div>
            {{
              [
                "友情ボーナス",
                "やる気効果上昇",
                "練習ボーナス",
                "練習効果上昇",
                "初期値上昇",
                "初期絆ゲージ",
                "レースボーナス",
                "ファンボーナス",
                "ヒントLv上昇",
                "ヒント率上昇",
                "得意率上昇",
                "イベ回復量上昇",
                "イベ効果上昇",
                "失敗率ダウン",
                "体力消費ダウン",
                "スキルPt",
                "賢さ友情回復量",
              ][i - 1]
            }}
          </div>
        </div>
      </div>
    </div>

    <!-- Deck 2 -->
    <div
      class="xl:col-span-5 flex-col items-center"
      :class="{
        flex: showSecondDeck,
        hidden: !showSecondDeck,
        'xl:flex': !showSecondDeck,
      }"
    >
      <deck-info
        ref="secondDeck"
        :displayContent="displayContent"
        :left="false"
        @updateSavedDecks="updateSavedDecksSecond"
      />
    </div>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";
import DeckInfo from "./DeckInfo.vue";

export default defineComponent({
  name: "DeckCompare",
  components: { DeckInfo },

  data: function () {
    return {
      showSecondDeck: false,
    };
  },

  props: {
    displayContent: {
      type: String,
      required: true,
    },
  },

  methods: {
    updateSavedDecksFirst: function () {
      (this.$refs.secondDeck as typeof DeckInfo).reloadLocalStorage();
    },

    updateSavedDecksSecond: function () {
      (this.$refs.firstDeck as typeof DeckInfo).reloadLocalStorage();
    },
  },

  watch: {
    showSecondDeck: function () {
      this.$nextTick(() => {
        (this.$refs.firstDeck as typeof DeckInfo).updateCardsFontSize();
        (this.$refs.secondDeck as typeof DeckInfo).updateCardsFontSize();
      });
    },
  },
});
</script>

<style scoped>
input:checked ~ .dot {
  transform: translateX(133.333%);
}
</style>
