<template>
  <nav class="sticky top-0 z-30 w-full shadow-md px-1 md:px-6 bg-pink-400">
    <div class="relative flex items-center justify-between h-12 md:h-14">
      <!-- Mobile menu button -->
      <div class="absolute inset-y-0 left-0 flex items-center md:hidden">
        <button
          class="inline-flex items-center justify-center p-2 rounded-md text-gray-200"
          @click="toggleMobileMenu"
        >
          <span class="sr-only">Open main menu</span>
          <svg
            class="h-6 w-6"
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
            aria-hidden="true"
            v-if="!showMobileMenu"
          >
            <path
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width="2"
              d="M4 6h16M4 12h16M4 18h16"
            />
          </svg>
          <svg
            class="h-6 w-6"
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
            aria-hidden="true"
            v-else
          >
            <path
              stroke-linecap="round"
              stroke-linejoin="round"
              stroke-width="2"
              d="M6 18L18 6M6 6l12 12"
            />
          </svg>
        </button>
      </div>

      <div class="flex-1 flex items-stretch justify-center md:justify-start">
        <!-- Title -->
        <div class="flex-shrink-0 flex items-center">
          <a href="#" class="text-white text-xl">ウマ娘 計算機置き場</a>
        </div>

        <!-- Buttons -->
        <div class="ml-10 hidden md:block">
          <div class="flex space-x-5">
            <div
              v-for="item in menu"
              :key="item.value"
              class="flex relative h-14 items-center"
              :class="{
                'menu-item': true,
                'active-item': modelValue == item.value,
                'text-white': modelValue == item.value,
                'text-gray-200': modelValue != item.value,
              }"
            >
              <a href="#" class="hover:text-white px-2 py-1" @click="switchTab(item.value)">
                {{ item.text }}
              </a>
            </div>
          </div>
        </div>
      </div>
    </div>
  </nav>

  <!-- Mobile menu -->
  <transition name="mobile-menu">
    <div v-if="showMobileMenu" class="sticky top-12 z-20 p-3 space-y-3 shadow-md bg-pink-400">
      <div v-for="item in menu" :key="item.value">
        <a
          href="#"
          class="relative inline-block hover:text-white px-2 py-1 rounded-md"
          :class="{
            'menu-item': true,
            'active-item': modelValue == item.value,
            'text-white': modelValue == item.value,
            'text-gray-200': modelValue != item.value,
          }"
          @click="switchTab(item.value)"
        >
          {{ item.text }}
        </a>
      </div>
    </div>
  </transition>
</template>

<script lang="ts">
import { defineComponent } from "vue";

export default defineComponent({
  name: "Header",
  emits: ["update:modelValue"],
  data: function () {
    return {
      showMobileMenu: false,
      menu: [
        { value: "deckEffect", text: "デッキ効果一覧" },
        { value: "deckTraining", text: "デッキ練習性能" },
        { value: "stats", text: "基礎ステータス" },
      ],
    };
  },
  props: {
    modelValue: {
      type: String,
      required: true,
    },
  },
  methods: {
    switchTab: function (active: string) {
      this.showMobileMenu = false;
      if (active !== this.modelValue) {
        this.$emit("update:modelValue", active);
      }
    },
    toggleMobileMenu: function () {
      this.showMobileMenu = !this.showMobileMenu;
    },
  },
});
</script>

<style scoped>
.menu-item::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  display: block;
  border-bottom-width: 3px;
  border-color: #fcd34d;
  opacity: 0;
  transition-property: opacity;
  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
  transition-duration: 250ms;
}

.menu-item.active-item::after {
  opacity: 1;
}

.mobile-menu-enter-active {
  transition-property: transform;
  transition-duration: 200ms;
  transition-timing-function: cubic-bezier(0, 0, 0.2, 1);
}

.mobile-menu-leave-active {
  transition-property: transform;
  transition-duration: 100ms;
  transition-timing-function: cubic-bezier(0.4, 0, 1, 1);
}

.mobile-menu-enter-from,
.mobile-menu-leave-to {
  transform: translateY(-100%);
}
</style>
